import Foundation
import Combine
import Network

import VenuesAPI
import UserLocation
import ImageLoader

import VenuesStore
import LocationStore

import class UIKit.UIImage

@MainActor
public final class VenueFeatureViewModel: ObservableObject {

  private let venuesStore: any VenuesStoreProtocol
  private let locationStore: any LocationStoreProtocol
  private let imageCache: any ImageCache

  @Published var requestState: VenuesFeature.VenuesListRequestState? = .loading(initial: true)
  @Published var venues: [Venue] = []

  let errorToast = PassthroughSubject<String, Never>()

  /// Maximum number of results to display
  let maxResults = 15

  private var imageLoadingTask: Task<Void, Never>?

  private var currentLocation: LocationCoordinate2D = .init(latitude: 0, longitude: 0)
  private var hasNetworkConnection = false

  private var backgroundTasks: [Task<Void, Never>] = []

  init(
    venuesStore: any VenuesStoreProtocol,
    locationStore: any LocationStoreProtocol,
    imageCache: any ImageCache
  ) {
    self.venuesStore = venuesStore
    self.locationStore = locationStore
    self.imageCache = imageCache

    // Keep track of location updates in background task
    backgroundTasks.append(
      updateVenuesOnLocationChange()
    )

    // Keep track of favorite venues updates in background task
    backgroundTasks.append(
      updateFavoriteVenues()
    )
  }

  deinit {
    // Cancel all background tasks
    for task in backgroundTasks {
      task.cancel()
    }

    print("\(Self.self) deinit")
  }

}

// MARK: - View Actions

extension VenueFeatureViewModel {

  func loadVenuesForCurrentLocation() {
    Task { await updateVenues() }
  }

  func loadImage(for remoteUrl: URL, size: CGSize) async ->  UIImage? {
    await imageCache.thumbnailImage(for: remoteUrl, size: size)
  }
}

// MARK: - Private

private extension VenueFeatureViewModel {

  func updateVenuesOnLocationChange() -> Task<Void, Never> {
    Task { [weak self, locationStore] in
      for await location in locationStore.location.values {
        // When self is released, end the unstructured task and stop listening for location updates
        guard let self else { break }

        // Store current location
        currentLocation = location

        await self.updateVenues()
      }

      print("Location update task finished")
    }
  }

  func updateFavoriteVenues() -> Task<Void, Never> {
    Task { [$venues, venuesStore] in
      for await venues in $venues.values {
        var fav = Set<Venue.ID>()
        var notFav = Set<Venue.ID>()

        for venue in venues {
          if venue.isFavorite {
            fav.insert(venue.id)
          } else {
            notFav.insert(venue.id)
          }
        }

        venuesStore.storeFavoriteVenues(fav, notFav)
      }

      print("Favorite venues update task finished")
    }
  }

  private func updateVenues() async {
    // Cancel the previous image loading task
    imageLoadingTask?.cancel()

    let initial = switch requestState {
    case nil: false
    case .error(_, let initial), .loading(let initial): initial
    }

    self.requestState = .loading(initial: initial)

    // Load venues for the current location
    do {
      venues = Array(
        try await venuesStore
          .getVenues(for: currentLocation)
          .prefix(maxResults)
      )

      requestState = nil
    } catch {
      requestState = .error(error, initial: initial)
      if !initial {
        errorToast.send(error.localizedDescription)
      }
    }
  }
}
