    var thumbnailImageResult: UIImage?
    var thumbnailImageCallCount = 0
    var lastRequestedURL: URL?
    var lastRequestedSize: CGSize?

    func thumbnailImage(for url: URL, size: CGSize) async -> UIImage? {
        thumbnailImageCallCount += 1
        lastRequestedURL = url
        lastRequestedSize = size
        return thumbnailImageResult
    }
}

// MARK: - Test Class
