extension VenuesViewModelTest {

    @MainActor
    func test_venuesLoadingError() async throws {
        // Given
        let imageCache = MockImageCache()
        let sut = VenueFeatureViewModel(
            venuesStore: venuesStore,
            locationStore: locationStore,
            imageCache: imageCache
        )

        struct TestError: Error, LocalizedError {
            var errorDescription: String? { "Test error" }
        }
        venuesStore.getVenuesResult = .failure(TestError())

        var capturedToastMessage: String?
        let toastExpectation = expectation(description: "Toast message received")

        let cancellable = sut.errorToast.sink { message in
            capturedToastMessage = message
            toastExpectation.fulfill()
        }

        // When
        let testLocation = LocationCoordinate2D(latitude: 40.7128, longitude: -74.0060)
        locationStore.simulateLocationUpdate(testLocation)

        // Then
        await fulfillment(of: [toastExpectation], timeout: 1.0)

        if case .error(let error, initial: false) = sut.requestState {
            XCTAssertTrue(error is TestError)
        } else {
            XCTFail("Expected error state")
        }

        XCTAssertEqual(capturedToastMessage, "Test error")
        XCTAssertTrue(sut.venues.isEmpty)
        XCTAssertEqual(venuesStore.getVenuesCallCount, 1)

        cancellable.cancel()
    }
}
