    @MainActor
    func test_loadVenuesForCurrentLocation() async throws {
        // Given
        let imageCache = MockImageCache()
        let sut = VenueFeatureViewModel(
            venuesStore: venuesStore,
            locationStore: locationStore,
            imageCache: imageCache
        )

        let testVenues = [
            Venue(
                id: "1",
                titleString: "Venue 1",
                descriptionString: "",
                remoteImageUrl: URL(string: "https://example.com/1.jpg")!,
                isFavorite: false
            ),
            Venue(
                id: "2",
                titleString: "Venue 2",
                descriptionString: "",
                remoteImageUrl: URL(string: "https://example.com/2.jpg")!,
                isFavorite: true
            )
        ]
        venuesStore.getVenuesResult = .success(testVenues)

        // When
        await sut.loadVenuesForCurrentLocation()

        // Then
        XCTAssertEqual(venuesStore.getVenuesCallCount, 1)
        XCTAssertEqual(sut.venues, testVenues)
        XCTAssertNil(sut.requestState) // Loading should be complete
    }

    @MainActor
    func test_loadImage() async throws {
        // Given
        let imageCache = MockImageCache()
        let sut = VenueFeatureViewModel(
            venuesStore: venuesStore,
            locationStore: locationStore,
            imageCache: imageCache
        )

        let testImage = UIImage()
        imageCache.thumbnailImageResult = testImage

        let testURL = URL(string: "https://example.com/image.jpg")!
        let testSize = CGSize(width: 100, height: 100)

        // When
        let result = await sut.loadImage(for: testURL, size: testSize)

        // Then
        XCTAssertEqual(imageCache.thumbnailImageCallCount, 1)
        XCTAssertEqual(imageCache.lastRequestedURL, testURL)
        XCTAssertEqual(imageCache.lastRequestedSize, testSize)
        XCTAssertIdentical(result as AnyObject, testImage as AnyObject)
    }

    @MainActor
    func test_loadVenuesForCurrentLocation_respectsMaxResults() async throws {
        // Given
        let imageCache = MockImageCache()
        let sut = VenueFeatureViewModel(
            venuesStore: venuesStore,
            locationStore: locationStore,
            imageCache: imageCache
        )

        // Create more venues than maxResults (15)
        let testVenues = (1...20).map { index in
            Venue(
                id: "\(index)",
                titleString: "Venue \(index)",
                descriptionString: "",
                remoteImageUrl: URL(string: "https://example.com/\(index).jpg")!,
                isFavorite: false
            )
        }
        venuesStore.getVenuesResult = .success(testVenues)

        // When
        await sut.loadVenuesForCurrentLocation()

        // Then
        XCTAssertEqual(sut.venues.count, sut.maxResults)
        XCTAssertEqual(sut.venues.count, 15)
        XCTAssertEqual(sut.venues.map { $0.id }, testVenues.prefix(15).map { $0.id })
    }
}
